def contradicts(a: str, b: str) -> bool:
    """True when two spans assert OPPOSITE directions. Such a pair is a CONTRAST, never a merge."""
    pa, pb = polarity(a), polarity(b)
    return bool(pa and pb and pa != pb and not (pa & pb))

